const axios = require('axios');

exports.main = async (event, callback) => {

const HUBSPOT_TOKEN = process.env.HUBSPOT_PRIVATE_APP_TOKEN;

const headers = {
  Authorization: `Bearer ${HUBSPOT_TOKEN}`,
  "Content-Type": "application/json"
};

/* -------- DELAY FUNCTION -------- */

function delay(ms){
  console.log("Delay started at:", new Date().toISOString());
  return new Promise(resolve =>
    setTimeout(() => {
      console.log("Delay finished at:", new Date().toISOString());
      resolve();
    }, ms)
  );
}

try {

/* ---------------- GET WORKFLOW CONTACT ---------------- */

const contactId = event.object.objectId;

console.log("Workflow Contact ID:", contactId);

/* ---------------- READ CONTACT PROPERTIES ---------------- */

const contactRes = await axios.get(
`https://api.hubapi.com/crm/v3/objects/contacts/${contactId}?properties=hs_lead_status,email,hubspot_owner_id`,
{ headers }
);
await delay(10000); // delay

const properties = contactRes.data.properties || {};
const ownerId = properties.hubspot_owner_id || null;

console.log("Full Contact Properties:", properties);

const leadStatus = properties.hs_lead_status || null;

console.log("Lead Status:", leadStatus);

/* ---------------- CHECK LEAD STATUS ---------------- */

if (leadStatus === "OPEN") {


  await axios.post(
    "https://api.hubapi.com/crm/v3/objects/tasks",
    {
      properties: {
        hs_task_subject: "Follow up with OPEN lead",
        hs_task_body: "This task was created automatically because lead status is OPEN.",
        hs_task_status: "NOT_STARTED",
        hs_task_priority: "HIGH",
        hubspot_owner_id: ownerId, 
        hs_timestamp: new Date().toISOString()
      },
      associations: [
        {
          to: { id: contactId },
          types: [
            {
              associationCategory: "HUBSPOT_DEFINED",
              associationTypeId: 204
            }
          ]
        }
      ]
    },
    { headers }
  );
await delay(10000); // delay

  console.log("Task created for contact:", contactId);

  return;
}

/* ---------------- UPDATE LEAD STATUS ---------------- */

console.log("Lead Status not OPEN → Updating to CONNECTED");

await axios.patch(
`https://api.hubapi.com/crm/v3/objects/contacts/${contactId}`,
{
  properties: {
    hs_lead_status: "CONNECTED"
  }
},
{ headers }
);

await delay(10000); // delay

console.log("Lead Status Updated to CONNECTED");


/* ---------------- SEARCH CONTACT WITH EMAIL (PAGINATION) ---------------- */

console.log("Searching contact with email = bh@hubspot.com");

let after = null;
let foundContactId = null;

do {
const searchRes = await axios.post(
"https://api.hubapi.com/crm/v3/objects/contacts/search",
{
  limit: 2, // fetch only 2 contacts per page
  after: after,
  filterGroups: [
    {
      filters: [
        {
          propertyName: "email",
          operator: "EQ",
          value: "bh@hubspot.com"
        }
      ]
    }
  ]
},
{ headers }
);
  await delay(10000); // delay

console.log("Search Response:", JSON.stringify(searchRes.data, null, 2));await delay(10000); // 10 sec delay after API call

const results = searchRes.data.results || [];

console.log("Fetched contacts:", results.length);

if(results.length > 0){
    foundContactId = results[0].id;
    break;
}

after = searchRes.data?.paging?.next?.after || null;

} while(after);


/* ---------------- CHECK IF CONTACT FOUND ---------------- */

if (!foundContactId) {

  console.log("No contact found with email bh@hubspot.com");
  return;

}

console.log("Found contact ID to delete:", foundContactId);


/* ---------------- DELETE CONTACT ---------------- */

await axios.delete(
`https://api.hubapi.com/crm/v3/objects/contacts/${foundContactId}`,
{ headers }
);


console.log("Contact with email bh@hubspot.com deleted");

}

catch(error){

console.error(
"HubSpot API Error:",
error.response?.data || error.message
);

}

};

const axios = require('axios');

exports.main = async (event, callback) => {

const HUBSPOT_TOKEN = process.env.HUBSPOT_PRIVATE_APP_TOKEN;

const headers = {
  Authorization: `Bearer ${HUBSPOT_TOKEN}`,
  "Content-Type": "application/json"
};

try {

/* ---------------- CONTACT DATA ---------------- */

const email = "testuser123@demo.com";   // change or map from workflow
const firstname = "yayayayayyay";
const lastname = "User";
const company = "Demo Company";

/* ---------------- UPSERT CONTACT ---------------- */

const response = await axios.post(
"https://api.hubapi.com/crm/v3/objects/contacts/batch/upsert",
{
  inputs: [
    {
      idProperty: "email",
      id: email,
      properties: {
        email: email,
        firstname: firstname,
        lastname: lastname,
        company: company
      }
    }
  ]
},
{ headers }
);

/* ---------------- LOG RESULT ---------------- */

console.log("Contact Upsert Successful");

const contactId = response.data.results[0]?.id;

console.log("Contact ID:", contactId);
console.log("Full Response:", JSON.stringify(response.data, null, 2));

// callback({
//   outputFields: {
//     contactId: contactId
//   }
// });

}
catch(error){


console.error("ERROR MESSAGE:", error.message);

if(error.response){
  console.error("STATUS:", error.response.status);
  console.error("HUBSPOT RESPONSE:", JSON.stringify(error.response.data, null, 2));
}


callback({
  outputFields: {
    status: "failed"
  }
});

}

};

