const axios = require('axios');

exports.main = async (event, callback) => {

const HUBSPOT_TOKEN = process.env.HUBSPOT_PRIVATE_APP_TOKEN;

const headers = {
  Authorization: `Bearer ${HUBSPOT_TOKEN}`,
  "Content-Type": "application/json"
};

try {

let after = null;
let hasMore = true;
let totalContacts = 0;

while (hasMore) {

  let url = "https://api.hubapi.com/crm/v3/objects/contacts?limit=2";

  if(after){
    url += `&after=${after}`;
  }

  console.log("Calling API:", url);

  const response = await axios.get(url, { headers });

  const contacts = response.data.results;

  console.log(`Contacts returned in this page: ${contacts.length}`);

  /* Print each contact */

  contacts.forEach((contact, index) => {

    const email = contact.properties.email;
    const firstname = contact.properties.firstname;
    const lastname = contact.properties.lastname;

    console.log(
      `Contact ${totalContacts + index + 1}: ${firstname} ${lastname} (${email})`
    );

  });

  totalContacts += contacts.length;

  /* Pagination */

  const paging = response.data.paging;

  if(paging && paging.next){
    after = paging.next.after;
    console.log("Next pagination cursor:",after);
   hasMore=false; 
  }
  else{
    hasMore = false;
  }

}

console.log("Total Contacts Retrieved:", totalContacts);

callback({
  outputFields: {
    totalContacts: totalContacts
  }
});

}
catch(error){

console.error(
"HubSpot API Error:",
error.response?.data || error.message
);

throw error;

}

};

const axios = require('axios');

exports.main = async (event, callback) => {

  const HUBSPOT_TOKEN = process.env.HUBSPOT_PRIVATE_APP_TOKEN;

  const headers = {
    Authorization: `Bearer ${HUBSPOT_TOKEN}`,
    "Content-Type": "application/json"
  };

  try {
    // 1️⃣ Get email from workflow input field
    const email = event.inputFields.email;

    if (!email) {
      throw new Error("Email is required");
    }

    console.log("Searching contact with email:", email);

    // 2️⃣ Search Contact by Email
    const searchRes = await axios.post(
      "https://api.hubapi.com/crm/v3/objects/contacts/search",
      {
        filterGroups: [
          {
            filters: [
              {
                propertyName: "email",
                operator: "EQ",
                value: email
              }
            ]
          }
        ]
      },
      { headers }
    );

    const results = searchRes.data.results;

    if (!results || results.length === 0) {
      throw new Error("No contact found with this email");
    }

    const contactId = results[0].id;
    console.log("Contact Found ID:", contactId);

    // 3️⃣ Create Deal
    const dealRes = await axios.post(
      "https://api.hubapi.com/crm/v3/objects/deals",
      {
        properties: {
          dealname: `Deal for ${email}`,
          dealstage: "appointmentscheduled", // change as per your pipeline
          pipeline: "default",               // change if needed
          amount: "1000"
        }
      },
      { headers }
    );

    const dealId = dealRes.data.id;
    console.log("Deal Created ID:", dealId);

    // 4️⃣ Associate Deal with Contact
    await axios.put(
      `https://api.hubapi.com/crm/v3/objects/deals/${dealId}/associations/contacts/${contactId}/deal_to_contact`,
      {},
      { headers }
    );

    console.log("Deal associated with Contact successfully");

    // 5️⃣ Return output (optional)
    callback({
      outputFields: {
        contactId: contactId,
        dealId: dealId
      }
    });

  } catch (error) {
    console.error("Error:", error.response?.data || error.message);
    throw error;
  }
};

const axios = require('axios');

exports.main = async (event, callback) => {

  const HUBSPOT_TOKEN = process.env.HUBSPOT_PRIVATE_APP_TOKEN;

  const headers = {
    Authorization: `Bearer ${HUBSPOT_TOKEN}`,
    "Content-Type": "application/json"
  };

  try {

    let after = null;       // pagination cursor
    let hasMore = true;     // loop control
    let totalContacts = 0;  // counter

    console.log("Starting bulk contact fetch...");

    while (hasMore) {

      // 1️⃣ Fetch contacts with pagination
      const res = await axios.get(
        "https://api.hubapi.com/crm/v3/objects/contacts",
        {
          headers,
          params: {
            limit: 2, // max allowed per request
            after: after,
            properties: "email"
          }
        }
      );

      const contacts = res.data.results || [];

      console.log(`Fetched ${contacts.length} contacts`);

      // 2️⃣ Print emails
      contacts.forEach((contact, index) => {
        const email = contact.properties?.email || "No Email";
        console.log(`Contact ${totalContacts + index + 1}: ${email}`);
      });

      totalContacts += contacts.length;

      // 3️⃣ Handle pagination
      after = res.data?.paging?.next?.after || null;

      if (!after) {
        hasMore = false;
      } else {
        console.log("Moving to next page, after:", after);
      }
    }

    console.log("Total Contacts Fetched:", totalContacts);

    // Optional output
    callback({
      outputFields: {
        totalContacts: totalContacts
      }
    });

  } catch (error) {
    console.error("Error:", error.response?.data || error.message);
    throw error;
  }
};

const axios = require("axios");

exports.main = async (event, callback) => {

  const HUBSPOT_TOKEN = process.env.HUBSPOT_PRIVATE_APP_TOKEN;

  // dynamic contact id
  const contactIds = [{ id: event.object.objectId }];

  try {

    const contactsResponse = await axios.post(
      "https://api.hubapi.com/crm/v3/objects/contacts/batch/read",
      {
        inputs: contactIds,
        properties: ["firstname","lastname","email"],
        propertiesWithHistory: []
      },
      {
        headers: {
          Authorization: `Bearer ${HUBSPOT_TOKEN}`,
          "Content-Type": "application/json"
        }
      }
    );

    console.log(JSON.stringify(contactsResponse.data, null, 2));

    callback({
      outputFields: {
        contacts: JSON.stringify(contactsResponse.data.results)
      }
    });

  } catch (error) {
    console.error(error.response?.data || error.message);
    throw error;
  }

};
